const rawKeywords = $('Read Keywords').all();
const rawChannels = $('Read Channels').all();

let keywords = [];
let stop_words = [];
let intents = [];
let chats = [];
let channels_com = [];

// 1. Обработка ключей, стоп-слов и интентов
rawKeywords.forEach(item => {
    const row = item.json;
    for (const key in row) {
        const cleanKey = key.toLowerCase().trim();
        const val = String(row[key]).trim().toLowerCase();

        if (!val || val === 'undefined' || val === 'null' || val.length < 2) continue;

        if (cleanKey.includes('stop')) {
            stop_words.push(val);
        } 
        else if (cleanKey.includes('intent')) {
            intents.push(val);
        } 
        else if (cleanKey.includes('word')) {
            keywords.push(val);
        }
    }
});

// 2. Раздельная обработка чатов и каналов для комментов
rawChannels.forEach(item => {
    const row = item.json;

    const chatVal = row['channels'] || row['Channels'];
    if (chatVal && String(chatVal).trim() !== 'undefined' && String(chatVal).trim() !== 'null') {
        const cleanChat = String(chatVal).trim();
        if (cleanChat.length >= 3) chats.push(cleanChat);
    }

    const channelComVal = row['channels_com'] || row['Channels_com'];
    if (channelComVal && String(channelComVal).trim() !== 'undefined' && String(channelComVal).trim() !== 'null') {
        const cleanChannel = String(channelComVal).trim();
        if (cleanChannel.length >= 3) channels_com.push(cleanChannel);
    }
});

return {
    keywords: [...new Set(keywords)],
    stop_words: [...new Set(stop_words)],
    intents: [...new Set(intents)],
    chats: [...new Set(chats)],
    channels_com: [...new Set(channels_com)]
};
